noncompliant:
if (condition)
    doSomething();
    doSomethingElse(); // Noncompliant: misleading indentation

for (int i = 0; i < 10; i++)
    process(i);
    cleanup(); // Noncompliant: cleanup runs only once

compliant:
if (condition) {
    doSomething();
    doSomethingElse(); // Compliant: proper braces
}

for (int i = 0; i < 10; i++) {
    process(i);
}
cleanup(); // Compliant: clear intent
